1	const CURSED_SURCHARGE_RATE = 0.1;
2	const HIGH_ENCHANTMENT_THRESHOLD = 5;
3	const HIGH_ENCHANTMENT_SURCHARGE = 20;
4	const LOYALTY_DISCOUNT_RATE = 0.1;
5	const LOYALTY_THRESHOLD = 2;
6	const FOLLOW_UP_DISCOUNT_RATE = 0.05;
7	
8	interface PolicyItem {
9	  baseCost: number;
10	  cursed?: boolean;
11	  enchantment?: number;
12	}
13	
14	interface LoyaltyInfo {
15	  years?: number;
16	  followUp?: boolean;
17	}
18	
19	function calculateItemCost(item: PolicyItem): number {
20	  let effectiveCost = item.baseCost + (item.cursed ? item.baseCost * CURSED_SURCHARGE_RATE : 0);
21	  if (item.enchantment && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
22	    effectiveCost += HIGH_ENCHANTMENT_SURCHARGE;
23	  }
24	  return effectiveCost;
25	}
26	
27	function hasEligibleLoyalty(loyalty?: unknown): boolean {
28	  const loyaltyInfo = loyalty as LoyaltyInfo;
29	  return loyaltyInfo?.years !== undefined && loyaltyInfo.years >= LOYALTY_THRESHOLD;
30	}
31	
32	function isFollowUpContract(loyalty?: unknown): boolean {
33	  const loyaltyInfo = loyalty as LoyaltyInfo;
34	  return loyaltyInfo?.followUp === true;
35	}
36	
37	const PROCESSING_FEE = 5;
38	const INSURANCE_SURCHARGE_RATE = 0.11;
39	
40	function applyLoyaltyAdjustment(baseTotal: number, loyalty?: unknown): number {
41	  if (hasEligibleLoyalty(loyalty)) {
42	    return baseTotal - (baseTotal * LOYALTY_DISCOUNT_RATE);
43	  } else if (isFollowUpContract(loyalty)) {
44	    return baseTotal - (baseTotal * FOLLOW_UP_DISCOUNT_RATE);
45	  } else {
46	    return baseTotal + (baseTotal * INSURANCE_SURCHARGE_RATE) + PROCESSING_FEE;
47	  }
48	}
49	
50	export function quotePolicy(items: unknown, loyalty?: unknown): number {
51	  const policyItems = items as PolicyItem[];
52	  const total = policyItems.reduce((sum, item) => sum + calculateItemCost(item), 0);
53	  return applyLoyaltyAdjustment(total, loyalty);
54	}
